import{_ as l,c as r,o as a,a6 as i}from"./chunks/framework.D3k0dqWr.js";const u=JSON.parse('{"title":"Blender","description":"","frontmatter":{},"headers":[],"relativePath":"Docs/Knowledge/Tools/Blender/Blender.md","filePath":"Docs/Knowledge/Tools/Blender/Blender.md","lastUpdated":1758515042000}'),n={name:"Docs/Knowledge/Tools/Blender/Blender.md"};function t(d,e,o,s,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="blender" tabindex="-1">Blender <a class="header-anchor" href="#blender" aria-label="Permalink to &quot;Blender&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">提示</p><p>这一篇文档是我根据视频 <a href="https://www.bilibili.com/video/BV14u41147YH" target="_blank" rel="noreferrer">[Kurt]Blender零基础入门教程 | Blender中文区新手必刷教程(已完结)</a> 边学习边写的, 可能会有一些错误, 欢迎指正.</p></div><h2 id="什么是-blender" tabindex="-1">什么是 Blender <a class="header-anchor" href="#什么是-blender" aria-label="Permalink to &quot;什么是 Blender&quot;">​</a></h2><p><strong>Blender</strong> 是一款开源, 免费的 3D 创建软件, 支持从建模/雕刻/材质与贴图/渲染/动画到视频剪辑的全流程工作.</p><p>它可以应用于:</p><ul><li>建模: 创建静态或动态的三维模型.</li><li>动画与绑定: 角色动画/骨骼绑定/动作捕捉.</li><li>渲染: 支持 Eevee(实时渲染)和 Cycles(光线追踪).</li><li>游戏开发: 模型和动画导出至游戏引擎.</li><li>特效: 流体/烟雾/布料/粒子特效.</li><li>视频后期: 剪辑/合成/色彩校正.</li></ul><p><strong>Blender</strong> 社区活跃, 有大量免费插件和教程, 是独立创作者/设计师以及专业工作室常用工具.</p><h2 id="blender-的特点" tabindex="-1">Blender 的特点 <a class="header-anchor" href="#blender-的特点" aria-label="Permalink to &quot;Blender 的特点&quot;">​</a></h2><ul><li>免费开源: 任何人都可以使用和二次开发.</li><li>跨平台: Windows/macOS/Linux 都支持.</li><li>功能全面: 从建模到渲染几乎无需切换软件.</li><li>活跃社区: 有大量教程/插件和素材库.</li><li>实时渲染与高质量渲染并存: Eevee 适合快速预览, Cycles 支持高精度渲染.</li></ul><h2 id="blender-的应用场景" tabindex="-1">Blender 的应用场景 <a class="header-anchor" href="#blender-的应用场景" aria-label="Permalink to &quot;Blender 的应用场景&quot;">​</a></h2><ul><li>影视动画: 短片/广告/3D 动画电影.</li><li>游戏开发: 建模/贴图/动画导出到 Unity/Unreal.</li><li>建筑可视化: 室内设计/建筑渲染.</li><li>产品设计: 概念设计/原型渲染.</li><li>教育与科研: 3D 可视化/仿真建模.</li></ul>',11)])])}const B=l(n,[["render",t]]);export{u as __pageData,B as default};
